#ifdef cl_khr_fp64
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef RD_WG_SIZE_0_0
#define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define NUMBER_THREADS RD_WG_SIZE
#else
#define NUMBER_THREADS 256
#endif

__kernel void extract_kernel(const long d_Ne,
                             __global float *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)bx * (long)NUMBER_THREADS + (long)tx;

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(const long d_Ne,
                             __global float *d_I,
                             __global float *d_sums,
                             __global float *d_sums2) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)bx * (long)NUMBER_THREADS + (long)tx;

    if (ei < d_Ne) {
        float v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(const long d_Ne,
                            const long d_no,
                            const int d_mul,
                            __global float *d_sums,
                            __global float *d_sums2,
                            const int d_blocks) {
    (void)d_Ne;

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)bx * (long)NUMBER_THREADS + (long)tx;

    int nf = NUMBER_THREADS - (d_blocks * NUMBER_THREADS - (int)d_no);
    int df = 0;
    int i;

    __local float d_psum[NUMBER_THREADS];
    __local float d_psum2[NUMBER_THREADS];

    if (ei < d_no) {
        long idx = ei * (long)d_mul;
        d_psum[tx] = d_sums[idx];
        d_psum2[tx] = d_sums2[idx];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if (((tx + 1) % i) == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (NUMBER_THREADS - 1)) {
            long out = (long)bx * (long)d_mul * (long)NUMBER_THREADS;
            d_sums[out] = d_psum[tx];
            d_sums2[out] = d_psum2[tx];
        }
    } else {
        if (bx != (d_blocks - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (((tx + 1) % i) == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (NUMBER_THREADS - 1)) {
                long out = (long)bx * (long)d_mul * (long)NUMBER_THREADS;
                d_sums[out] = d_psum[tx];
                d_sums2[out] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                int start = bx * NUMBER_THREADS + df;
                int end = bx * NUMBER_THREADS + nf;
                for (i = start; i < end; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                long out = (long)bx * (long)d_mul * (long)NUMBER_THREADS;
                d_sums[out] = d_psum[tx];
                d_sums2[out] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(const float lambda,
                          const int Nr,
                          const int Nc,
                          const long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global float *dN,
                          __global float *dS,
                          __global float *dW,
                          __global float *dE,
                          const float q0sqr,
                          __global float *c,
                          __global float *J) {
    (void)lambda;

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)bx * (long)NUMBER_THREADS + (long)tx;

    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei % (long)Nc);

        float Jc = J[ei];

        float dN_loc = J[(long)iN[row] * (long)Nc + (long)col] - Jc;
        float dS_loc = J[(long)iS[row] * (long)Nc + (long)col] - Jc;
        float dW_loc = J[(long)row * (long)Nc + (long)jW[col]] - Jc;
        float dE_loc = J[(long)row * (long)Nc + (long)jE[col]] - Jc;

        float G2 = (dN_loc * dN_loc + dS_loc * dS_loc + dW_loc * dW_loc + dE_loc * dE_loc) / (Jc * Jc);
        float L = (dN_loc + dS_loc + dW_loc + dE_loc) / Jc;

        float num = 0.5f * G2 - (1.0f / 16.0f) * (L * L);
        float den = 1.0f + 0.25f * L;
        float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        float c_loc = 1.0f / (1.0f + den);

        if (c_loc < 0.0f) c_loc = 0.0f;
        else if (c_loc > 1.0f) c_loc = 1.0f;

        dN[ei] = dN_loc;
        dS[ei] = dS_loc;
        dW[ei] = dW_loc;
        dE[ei] = dE_loc;
        c[ei] = c_loc;
    }
}

__kernel void srad2_kernel(const float lambda,
                           const int Nr,
                           const int Nc,
                           const long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global float *dN,
                           __global float *dS,
                           __global float *dW,
                           __global float *dE,
                           __global float *c,
                           __global float *J) {
    (void)Nr;
    (void)iN;
    (void)jW;

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)bx * (long)NUMBER_THREADS + (long)tx;

    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei % (long)Nc);

        float cN = c[ei];
        float cS = c[(long)iS[row] * (long)Nc + (long)col];
        float cW = c[ei];
        float cE = c[(long)row * (long)Nc + (long)jE[col]];

        float D = cN * dN[ei] + cS * dS[ei] + cW * dW[ei] + cE * dE[ei];

        J[ei] = J[ei] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(const long d_Ne,
                              __global float *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    long ei = (long)bx * (long)NUMBER_THREADS + (long)tx;

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
